import json
import urllib.request
import os

def build_databases():
    print("Запуск сборщика данных Академии (Версия 7.0)...")
    os.makedirs("data", exist_ok=True)

    # 1. Сборка Библии
    print("Скачивание Библии (Синодальный перевод)...")
    bible_url = "https://cdn.jsdelivr.net/gh/thiagobodruk/bible@master/json/ru_synodal.json"
    req = urllib.request.Request(bible_url, headers={'User-Agent': 'Mozilla/5.0'})
    with urllib.request.urlopen(req) as response:
        bible_raw = json.loads(response.read().decode())
    
    bible_map = {}
    for book in bible_raw:
        book_name = book['name']
        bible_map[book_name] = {}
        for c_idx, chapter in enumerate(book['chapters']):
            bible_map[book_name][str(c_idx + 1)] = {}
            for v_idx, verse in enumerate(chapter):
                bible_map[book_name][str(c_idx + 1)][str(v_idx + 1)] = verse
    with open("data/bible.json", "w", encoding="utf-8") as f:
        json.dump(bible_map, f, ensure_ascii=False, separators=(',', ':'))

    # 2. Сборка Корана
    print("Скачивание Корана (Перевод Кулиева)...")
    quran_url = "https://cdn.jsdelivr.net/npm/@fawazahmed0/quran-api@1/editions/rus-elmir-kuliev.json"
    req = urllib.request.Request(quran_url, headers={'User-Agent': 'Mozilla/5.0'})
    with urllib.request.urlopen(req) as response:
        quran_raw = json.loads(response.read().decode())
    
    quran_map = {}
    for item in quran_raw['quran']:
        surah_num = str(item['chapter'])
        if surah_num not in quran_map: quran_map[surah_num] = {"1": {}}
        quran_map[surah_num]["1"][str(item['verse'])] = item['text']
    with open("data/quran.json", "w", encoding="utf-8") as f:
        json.dump(quran_map, f, ensure_ascii=False, separators=(',', ':'))

    # 3. База Молитв (prayers.json)
    print("Генерация базы молитв и псалмов...")
    prayers_db = {
        "bible": [
            { "title": "Молитва Господня", "subtitle": "Отче Наш (Pater Noster)", "text": "Отче наш, сущий на небесах! да святится имя Твое; да приидет Царствие Твое; да будет воля Твоя и на земле, как на небе; хлеб наш насущный дай нам на сей день; и прости нам долги наши, как и мы прощаем должникам нашим; и не введи нас в искушение, но избавь нас от лукавого. Ибо Твое есть Царство и сила и слава во веки. Аминь.", "analysis": "Главная христианская молитва, данная самим Иисусом (Мф 6:9-13). Она содержит уникальное для античности обращение к Богу как к «Авва» (Отцу), что подчеркивает сыновнюю близость, а не рабский страх. Молитва состоит из 7 прошений: первые 3 касаются Бога, остальные 4 — нужд человека." },
            { "title": "Покаянный Псалом", "subtitle": "Псалом 50 (Мизмор Ле-Давид)", "text": "Помилуй меня, Боже, по великой милости Твоей, и по множеству щедрот Твоих изгладь беззакония мои... Сердце чистое сотвори во мне, Боже, и дух правый обнови внутри меня.", "analysis": "Написан царем Давидом после его глубокого нравственного падения (история с Вирсавией). Это эталон покаянной молитвы в иудео-христианской традиции. Теологический смысл: истинная жертва Богу — это не всесожжения (убийство животных), а «дух сокрушенный»." },
            { "title": "Молитва Защиты", "subtitle": "Псалом 90 (Живый в помощи)", "text": "Живущий под кровом Всевышнего под сенью Всемогущего покоится, говорит Господу: «прибежище мое и защита моя, Бог мой, на Которого я уповаю!» Он избавит тебя от сети ловца, от гибельной язвы...", "analysis": "Академически этот псалом относится к жанру «песней упования». Исторически он использовался еврейским народом, а затем и христианами, как сильнейшая молитва защиты от физических и демонических угроз (в тексте упоминаются 'ужасы в ночи' и 'стрелы, летящие днем')." },
            { "title": "Символ Веры", "subtitle": "Никео-Цареградский Символ", "text": "Верую во Единого Бога Отца, Вседержителя, Творца небу и земли, видимым же всем и невидимым. И во Единого Господа Иисуса Христа, Сына Божия... нас ради человек и нашего ради спасения сшедшаго с небес.", "analysis": "Не является молитвой в строгом смысле, но представляет собой догматический фундамент христианства. Был утвержден на Первом (325 г.) и Втором (381 г.) Вселенских соборах для защиты от ересей (арианства). В нем кристаллизовано учение о Троице и богочеловечности Христа." }
        ],
        "quran": [
            { "title": "Открывающая сура", "subtitle": "Аль-Фатиха", "text": "Во имя Аллаха, Милостивого, Милосердного! Хвала Аллаху, Господу миров, Милостивому, Милосердному, Властелину Дня воздаяния! Тебе одному мы поклоняемся и Тебя одного молим о помощи. Веди нас прямым путем...", "analysis": "Мать Корана (Умм аль-Китаб). Читается ежедневно от 17 раз в каждом ракаате намаза. Фатиха является диалогом: первая половина суры — это восхваление Бога, а вторая — просьба человека о наставлении. Согласно хадисам, Бог отвечает молящемуся на каждую произнесенную строку." },
            { "title": "Аят могущества", "subtitle": "Аят аль-Курси (2:255)", "text": "Аллах — нет божества, кроме Него, Живого, Вседержителя. Им не овладевают ни дремота, ни сон. Ему принадлежит то, что на небесах, и то, что на земле... Он знает их будущее и прошлое. Его Престол (Курси) объемлет небеса и землю.", "analysis": "Считается величайшим аятом Корана. В нем заключена совершенная концепция абсолютного монотеизма: Бог не подвержен человеческим слабостям (дремота, усталость). Слово «Курси» (Престол) в исламском богословии часто толкуется как метафора безграничного знания и власти Творца." },
            { "title": "Молитва Пророка Юнуса", "subtitle": "Дуа во чреве кита (21:87)", "text": "Нет божества, кроме Тебя! Пречист Ты! Воистину, я был одним из беззаконников. (Ля иляха илля анта, субханака, инни кунту миназ-залимин).", "analysis": "Молитва пророка Ионы (Юнуса), произнесенная им в отчаянии во чреве кита. В исламской экзегетике (тафсире) эта формула считается идеальным способом выхода из безвыходных ситуаций, так как она объединяет прославление Бога и искреннее признание собственной вины." },
            { "title": "Формула благословения", "subtitle": "Салават", "text": "Аллахумма салли аля Мухаммадин ва аля али Мухаммад, кама салляйта аля Ибрахима... (О Аллах, благослови Мухаммада и семейство Мухаммада, как благословил Ты Ибрахима...)", "analysis": "Особая молитва, которая не просит благ для самого молящегося, а просит Бога благословить пророка. Коран (33:56) устанавливает это как обязанность верующих. Чтение Салавата считается способом очистить сердце и выразить любовь к посланнику." }
        ]
    }
    with open("data/prayers.json", "w", encoding="utf-8") as f:
        json.dump(prayers_db, f, ensure_ascii=False, indent=2)

    # 4. База Энциклопедии (guide.json)
    print("Генерация энциклопедии 'Просто о сложном'...")
    guide_db = {
        "bible": [
            { "title": "Ветхий Завет: Тора (Пятикнижие)", "text": "Первые пять книг Библии (Бытие, Исход, Левит, Числа, Второзаконие). В них заложен фундамент авраамических религий: история сотворения мира, грехопадение, Всемирный потоп, история Авраама и вывод еврейского народа из Египта Моисеем. Главное ядро Торы — дарование 613 заповедей (включая Десять Заповедей) на горе Синай, которые сформировали моральный кодекс западной цивилизации." },
            { "title": "Ветхий Завет: Исторические книги и Пророки", "text": "Книги Иисуса Навина, Царств, Судей и труды великих пророков (Исаии, Иеремии). Они описывают кровавую и сложную историю Израиля: завоевание Ханаана, золотой век царя Давида, постройку Иерусалимского Храма Соломоном и последующее разрушение страны вавилонянами. Пророки здесь выступают не как 'предсказатели', а как строгие критики общества, призывающие царей и народ вернуться к социальной справедливости и Завету с Богом." },
            { "title": "Ветхий Завет: Писания (Мудрость и Поэзия)", "text": "Псалтирь, Книга Иова, Притчи и Екклесиаст. Это философская и поэтическая часть Библии. Если в Торе Бог говорит с человеком, то в Писаниях — человек отвечает Богу. Книга Иова, например, поднимает сложнейший философский вопрос теодицеи: почему в мире, которым управляет добрый Бог, страдают невинные и хорошие люди?" },
            { "title": "Новый Завет: Евангелия", "text": "Четыре книги (от Матфея, Марка, Луки и Иоанна), описывающие земную жизнь, учение, чудеса, распятие и воскресение Иисуса Христа. Евангелие переводится как 'Благая весть'. Авторы писали их для разных аудиторий: Матфей доказывал иудеям, что Иисус — это обещанный Мессия, Лука писал историческое исследование для греков, а Иоанн раскрывал глубокий философский смысл Христа как Божественного Слова (Логоса)." },
            { "title": "Новый Завет: Послания и Откровение", "text": "Письма апостолов (большинство написано апостолом Павлом) к первым христианским церквям. В них объясняется суть христианства: спасение достигается не просто соблюдением древних правил, а верой в жертву Христа. Завершает Библию книга 'Откровение' (Апокалипсис) — сложный мистический текст, наполненный символами, описывающий финальную победу добра над злом и создание 'Нового Иерусалима'." }
        ],
        "quran": [
            { "title": "Природа текста Корана", "text": "Слово 'Коран' означает 'Чтение вслух'. Мусульмане верят, что это не просто боговдохновенная книга, написанная людьми (как Библия), а несотворенная, прямая и дословная речь Самого Аллаха. Коран был передан пророку Мухаммеду через ангела Джибриля (Гавриила) не за один раз, а частями в течение 23 лет (с 610 по 632 год н.э.)." },
            { "title": "Мекканский период (Призыв и Вера)", "text": "Суры, ниспосланные в первые 13 лет в городе Мекка (86 сур). В это время мусульмане были гонимым меньшинством. Эти суры короткие, поэтичные, с мощным ритмом. Они посвящены базовым вещам: утверждению абсолютного Единобожия (Таухид), критике идолопоклонства, рассказам о древних пророках (Ное, Аврааме, Моисее) и живописному описанию грядущего Судного дня, Рая и Ада." },
            { "title": "Мединский период (Закон и Общество)", "text": "Суры, ниспосланные после переселения (Хиджры) мусульман в Медину, где Мухаммед стал главой государства (28 сур). Они длинные и прозаичные. Здесь Бог дает мусульманам основы Шариата: как правильно совершать молитву, как делить наследство, правила торговли, законы брака и развода, а также правила ведения войны и заключения мирных договоров." },
            { "title": "Концепция Пророчества", "text": "Ислам не отрицает библейских пророков, а интегрирует их. Коран упоминает Адама, Ибрахима (Авраама), Мусу (Моисея) и Ису (Иисуса) как великих посланников Ислама, которые несли одну и ту же истину. Однако мусульмане считают, что предыдущие писания (Тора и Евангелие) были искажены людьми со временем, и Коран был послан как финальная, защищенная от искажений 'печать' откровений." },
            { "title": "Тафсир и Сунна (Как понимать Коран)", "text": "Коран нельзя толковать произвольно. Для его понимания ученые используют 'Сунну' (предания о жизни и словах пророка Мухаммеда — хадисы). Если Коран говорит 'совершайте молитву', то именно Сунна объясняет, как физически ее делать. Также важна наука 'Асбаб ан-Нузуль' (причины ниспослания) — знание того, в ответ на какое историческое событие был ниспослан конкретный аят." }
        ]
    }
    with open("data/guide.json", "w", encoding="utf-8") as f:
        json.dump(guide_db, f, ensure_ascii=False, indent=2)
    print("Энциклопедия сохранена (data/guide.json).")
    print("Сборка успешно завершена! Теперь у вас 4 базы данных.")

if __name__ == "__main__":
    build_databases()
